#include <bits/stdc++.h>
using namespace std;
int ans=0,n,dp[1003][1003];
int main(){
    string s;
    cin>>s;
    n=s.size();
    s=" "+s;
    for(int len=2;len<=n;len++){
        for(int l=1,r=l+len-1;r<=n;l++,r++){
            if(s[l]==s[r])dp[l][r]=dp[l+1][r-1];
            else dp[l][r]=min(dp[l][r-1]+1,dp[l+1][r]+1);
        }
    }
    cout<<dp[1][n];
    return 0;
}
